import{c as t,S as h,j as a,m as o}from"./chunks/framework.8aa1YH_s.js";const u=JSON.parse('{"title":"Giỏ hàng & Thanh toán","description":"","frontmatter":{},"headers":[],"relativePath":"hoc-vien/gio-hang-thanh-toan.md","filePath":"hoc-vien/gio-hang-thanh-toan.md","lastUpdated":0}'),i={name:"hoc-vien/gio-hang-thanh-toan.md"};function r(g,n,c,l,e,d){return h(),a("div",null,[...n[0]||(n[0]=[o('<h1 id="gio-hang-thanh-toan" tabindex="-1">Giỏ hàng &amp; Thanh toán <a class="header-anchor" href="#gio-hang-thanh-toan" aria-label="Permalink to “Giỏ hàng &amp; Thanh toán”">​</a></h1><h2 id="gio-hang" tabindex="-1">Giỏ hàng <a class="header-anchor" href="#gio-hang" aria-label="Permalink to “Giỏ hàng”">​</a></h2><p><strong>Đường dẫn:</strong> <code>https://lamsonedutech.vn/luyen-tap/gio-hang/:id</code></p><h3 id="truy-cap-gio-hang" tabindex="-1">Truy cập giỏ hàng <a class="header-anchor" href="#truy-cap-gio-hang" aria-label="Permalink to “Truy cập giỏ hàng”">​</a></h3><ul><li>Bấm icon <strong>🛒 Giỏ hàng</strong> ở góc trên phải.</li><li>Hoặc sau khi bấm <strong>Thêm vào giỏ</strong> từ trang khóa.</li></ul><h3 id="tren-trang-gio-hang" tabindex="-1">Trên trang giỏ hàng <a class="header-anchor" href="#tren-trang-gio-hang" aria-label="Permalink to “Trên trang giỏ hàng”">​</a></h3><ul><li>Danh sách các khóa đã chọn (ảnh, tên, giá).</li><li>Có thể <strong>Xóa khóa khỏi giỏ</strong>.</li><li>Có thể <strong>Đổi số lượng</strong> (1 khóa thường mua 1, nhưng học liệu/sách có thể nhiều).</li><li><strong>Tổng tiền tạm tính</strong>.</li><li>Ô <strong>Mã khuyến mãi</strong> - nhập mã nếu có.</li></ul><h2 id="thanh-toan" tabindex="-1">Thanh toán <a class="header-anchor" href="#thanh-toan" aria-label="Permalink to “Thanh toán”">​</a></h2><p>Bấm <strong>Thanh toán</strong> ở giỏ hàng → vào trang <code>https://lamsonedutech.vn/luyen-tap/hoa-don/checkout</code>.</p><h3 id="buoc-1-xac-nhan-thong-tin" tabindex="-1">Bước 1: Xác nhận thông tin <a class="header-anchor" href="#buoc-1-xac-nhan-thong-tin" aria-label="Permalink to “Bước 1: Xác nhận thông tin”">​</a></h3><ul><li>Họ tên, SĐT, email - hệ thống tự điền từ hồ sơ.</li><li>Có thể chỉnh sửa nếu cần (vd: dùng email khác cho hóa đơn).</li><li>(Tùy chọn) Điền <strong>mã giới thiệu</strong> từ đại lý / giáo viên nếu có.</li></ul><h3 id="buoc-2-ap-dung-ma-khuyen-mai" tabindex="-1">Bước 2: Áp dụng mã khuyến mãi <a class="header-anchor" href="#buoc-2-ap-dung-ma-khuyen-mai" aria-label="Permalink to “Bước 2: Áp dụng mã khuyến mãi”">​</a></h3><ul><li>Gõ mã vào ô → bấm <strong>Áp dụng</strong>.</li><li>Nếu mã hợp lệ, giá được giảm ngay.</li><li>Có thể bỏ áp dụng để gõ mã khác.</li></ul><h3 id="buoc-3-chon-phuong-thuc-thanh-toan" tabindex="-1">Bước 3: Chọn phương thức thanh toán <a class="header-anchor" href="#buoc-3-chon-phuong-thuc-thanh-toan" aria-label="Permalink to “Bước 3: Chọn phương thức thanh toán”">​</a></h3><table tabindex="0"><thead><tr><th>Phương thức</th><th>Cách dùng</th></tr></thead><tbody><tr><td><strong>Chuyển khoản</strong></td><td>Hệ thống hiển thị tài khoản nhận tiền + QR code. Bạn chuyển khoản qua app ngân hàng.</td></tr><tr><td><strong>VNPay</strong></td><td>Bấm &quot;Thanh toán VNPay&quot; → quét QR hoặc nhập thẻ ATM/Visa.</td></tr><tr><td><strong>Momo</strong></td><td>Bấm &quot;Thanh toán Momo&quot; → mở app Momo → quét QR.</td></tr><tr><td><strong>ZaloPay</strong></td><td>Tương tự Momo.</td></tr><tr><td><strong>Thẻ Visa / Master</strong></td><td>Nhập số thẻ trực tiếp qua cổng thanh toán.</td></tr><tr><td><strong>Tiền mặt tại văn phòng</strong></td><td>Đến văn phòng trung tâm thanh toán.</td></tr></tbody></table><h3 id="buoc-4-hoan-tat" tabindex="-1">Bước 4: Hoàn tất <a class="header-anchor" href="#buoc-4-hoan-tat" aria-label="Permalink to “Bước 4: Hoàn tất”">​</a></h3><h4 id="voi-cong-thanh-toan-online-vnpay-momo-zalopay-visa" tabindex="-1">Với cổng thanh toán online (VNPay, Momo, ZaloPay, Visa) <a class="header-anchor" href="#voi-cong-thanh-toan-online-vnpay-momo-zalopay-visa" aria-label="Permalink to “Với cổng thanh toán online (VNPay, Momo, ZaloPay, Visa)”">​</a></h4><ul><li>Sau khi thanh toán thành công, hệ thống tự cập nhật <strong>trạng thái = Đã thanh toán</strong>.</li><li>Khóa học được kích hoạt ngay.</li><li>Bạn có thể vào <strong>Khóa học của tôi</strong> để bắt đầu học.</li></ul><h4 id="voi-chuyen-khoan" tabindex="-1">Với chuyển khoản <a class="header-anchor" href="#voi-chuyen-khoan" aria-label="Permalink to “Với chuyển khoản”">​</a></h4><ol><li>Sau khi chuyển khoản, <strong>chụp ảnh biên lai</strong>.</li><li>Vào trang <code>https://lamsonedutech.vn/luyen-tap/hoa-don/checkout2/:idReceipt</code> → tải biên lai lên.</li><li>Trung tâm sẽ <strong>xác nhận trong vòng 1-24 giờ</strong> (giờ hành chính).</li><li>Khi xác nhận xong, bạn nhận email + khóa được kích hoạt.</li></ol><blockquote><p>💡 Khi chuyển khoản, <strong>nội dung chuyển khoản phải có mã hóa đơn</strong> (vd: <code>HD20260512001</code>) để trung tâm khớp nhanh.</p></blockquote><h2 id="xem-lai-hoa-đon" tabindex="-1">Xem lại hóa đơn <a class="header-anchor" href="#xem-lai-hoa-đon" aria-label="Permalink to “Xem lại hóa đơn”">​</a></h2><p><strong>Đường dẫn:</strong> <code>https://lamsonedutech.vn/luyen-tap/nguoi-dung/hoa-don</code></p><ul><li>Liệt kê tất cả hóa đơn của bạn.</li><li>Bấm vào để xem chi tiết, tải PDF, in.</li></ul><h2 id="cac-trang-thai-hoa-đon" tabindex="-1">Các trạng thái hóa đơn <a class="header-anchor" href="#cac-trang-thai-hoa-đon" aria-label="Permalink to “Các trạng thái hóa đơn”">​</a></h2><table tabindex="0"><thead><tr><th>Trạng thái</th><th>Ý nghĩa</th></tr></thead><tbody><tr><td><strong>Chờ thanh toán</strong></td><td>Hóa đơn vừa tạo, chưa thanh toán hoặc chuyển khoản chưa được xác nhận</td></tr><tr><td><strong>Đã thanh toán</strong></td><td>Thành công, khóa đã được kích hoạt</td></tr><tr><td><strong>Đã hủy</strong></td><td>Bạn hoặc trung tâm đã hủy đơn</td></tr><tr><td><strong>Hoàn tiền</strong></td><td>Đã hoàn tiền cho bạn</td></tr></tbody></table><h2 id="huy-hoa-đon" tabindex="-1">Hủy hóa đơn <a class="header-anchor" href="#huy-hoa-đon" aria-label="Permalink to “Hủy hóa đơn”">​</a></h2><ul><li>Hóa đơn ở trạng thái <strong>Chờ thanh toán</strong> có thể tự hủy.</li><li>Đã thanh toán → cần liên hệ trung tâm yêu cầu hoàn tiền.</li></ul><h2 id="cau-hoi-thuong-gap" tabindex="-1">Câu hỏi thường gặp <a class="header-anchor" href="#cau-hoi-thuong-gap" aria-label="Permalink to “Câu hỏi thường gặp”">​</a></h2><p><strong>Tôi đã chuyển khoản 30 phút rồi mà chưa thấy khóa được mở?</strong> → Có thể trung tâm chưa xác nhận. Đợi tới giờ hành chính hoặc liên hệ hotline (gửi biên lai).</p><p><strong>Cổng thanh toán báo lỗi.</strong> → Thử lại sau vài phút hoặc đổi phương thức (Momo / chuyển khoản). Nếu vẫn lỗi, liên hệ trung tâm.</p><p><strong>Tôi nhập mã khuyến mãi nhưng báo &quot;không hợp lệ&quot;.</strong> → Kiểm tra: mã còn hạn? Mã áp dụng cho khóa bạn đang mua? Đơn đạt mức tối thiểu?</p><p><strong>Tôi muốn xuất hóa đơn VAT đỏ cho công ty.</strong> → Liên hệ trung tâm. Hệ thống mặc định cấp <strong>biên nhận điện tử</strong>; VAT đỏ xuất ngoài hệ thống.</p><p><strong>Mua khóa cho con / người khác?</strong> → Bạn vẫn dùng tài khoản của bạn để mua. Sau đó liên hệ trung tâm chuyển sở hữu khóa sang tài khoản người sử dụng, hoặc đăng ký tài khoản mới cho người đó.</p>',34)])])}const m=t(i,[["render",r]]);export{u as __pageData,m as default};
